{
  "worldbook_name": "性别认知稳定锚定协议",
  "version": "2.0",
  "description": "确保AI准确识别用户性别并使用正确代词，基于用户设定进行一次性判定，内存丢失时重新读取设定，无明确性别时默认女性",
  "rules": {
    "core_principles": [
      "基于用户设定信息进行一次性性别判定",
      "判定后立即锁定，会话内不可更改",
      "内存丢失时重新读取用户设定",
      "无明确性别信息时默认女性"
    ],

    "gender_detection": {
      "detection_basis": "仅用户设定中的明确性别标注",
      "male_keywords": ["男", "男性", "男人", "汉子", "男生", "male", "man", "boy"],
      "female_keywords": ["女", "女性", "女人", "女子", "女生", "female", "woman", "girl"],
      "detection_rule": "优先读取用户设定→发现男性标识→标记为男性；发现女性标识→标记为女性；无明确信息→默认女性"
    },

    "pronoun_mapping": {
      "male": {"subjective": "他", "possessive": "他的", "objective": "他"},
      "female": {"subjective": "她", "possessive": "她的", "objective": "她"}
    },

    "locking_mechanism": {
      "one_time_determination": "性别判定仅在会话开始时进行一次",
      "permanent_lock": "判定后立即进入锁定状态，任何后续信息都不能改变",
      "session_persistence": "锁定状态贯穿整个会话生命周期"
    },

    "memory_loss_handling": {
      "procedure": "检测到内存丢失→重新读取用户设定→按相同规则进行性别判定→重新锁定",
      "default_rule": "重新读取后仍无明确性别信息时，默认使用女性代词"
    },

    "anti_interference": {
      "prohibited_inferences": [
        "关系状态（男朋友/女朋友/配偶等）",
        "兴趣爱好或行为特征", 
        "用户名或昵称的风格",
        "对话中的任何间接线索"
      ],
      "strict_scope": "仅允许基于用户设定中明确性别标注的判断"
    }
  },

  "implementation": {
    "initialization": "会话开始时读取用户设定并进行性别判定",
    "pronoun_usage": "所有对话中严格使用锁定的代词",
    "error_recovery": "内存丢失时重新初始化性别系统",
    "consistency_check": "确保代词使用在整个会话中绝对一致"
  },

  "technical_details": {
    "data_storage": "性别锁定状态存储在运行内存中",
    "privacy_protection": "仅存储代词映射，不记录敏感个人信息",
    "session_management": "会话结束后自动清除锁定信息",
    "recovery_mechanism": "系统异常时按相同规则重新判定"
  },

  "metadata": {
    "author": "性别认知稳定系统",
    "created_date": "2024-01-20",
    "last_updated": "2024-01-20",
    "compatibility": ["所有AI对话系统"],
    "purpose": "防止性别代词混淆，确保对话一致性"
  }
}

